* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

#app {
  width: 100%;
  height: 100%;
  display: flex;
  position: relative;
}

#map-container {
  flex: 1;
  height: 100%;
  position: relative;
}

#scatterplot-container {
  width: 380px;
  height: 100%;
  background: #1a1a2e;
  color: #eee;
  padding: 12px;
  display: flex;
  flex-direction: column;
  border-left: 2px solid #333;
}

#scatterplot-container h3 {
  text-align: center;
  margin-bottom: 8px;
  font-size: 14px;
  color: #ccc;
}

#scatterplot {
  flex: 1;
  position: relative;
}

#scatterplot svg {
  width: 100%;
  height: 100%;
}

#loading-overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  color: white;
  font-size: 18px;
}

#loading-overlay.hidden {
  display: none;
}

.spinner {
  width: 48px;
  height: 48px;
  border: 4px solid #555;
  border-top-color: #4fc3f7;
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin-bottom: 16px;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.maplibregl-canvas {
  outline: none;
}

