input.content:
import type { Feature } from 'geojson';

const OVERPASS_URL = 'https://overpass-api.de/api/interpreter';

/**
 * Convert Overpass JSON elements to GeoJSON features.
 */
function elementsToGeoJSON(elements: OverpassElement[]): Feature[] {
  const nodes = new Map<number, [number, number]>();
  const ways = new Map<number, OverpassElement>();

  // Index nodes and ways
  for (const el of elements) {
    if (el.type === 'node' && el.lat !== undefined && el.lon !== undefined) {
      nodes.set(el.id, [el.lon, el.lat]);
    }
    if (el.type === 'way') {
      ways.set(el.id, el);
    }
  }

  const features: Feature[] = [];

  for (const el of elements) {
    if (el.type === 'way' && el.nodes) {
      const coords: [number, number][] = [];
      for (const nid of el.nodes) {
        const c = nodes.get(nid);
        if (c) coords.push(c);
      }
      if (coords.length < 2) continue;

      // Determine if polygon (closed way) or linestring
      const isClosed =
        coords.length >= 4 &&
        coords[0][0] === coords[coords.length - 1][0] &&
        coords[0][1] === coords[coords.length - 1][1];

      const feature: Feature = isClosed
        ? {
            type: 'Feature',
            properties: el.tags || {},
            geometry: { type: 'Polygon', coordinates: [coords] },
          }
        : {
            type: 'Feature',
            properties: el.tags || {},
            geometry: { type: 'LineString', coordinates: coords },
          };

      features.push(feature);
    } else if (el.type === 'relation' && el.members) {
      // Handle multipolygon relations
      const outerRings: [number, number][][] = [];
      for (const member of el.members) {
        if (member.type === 'way' && member.role === 'outer' && member.geometry) {
          const ring = member.geometry
            .filter((g: { lat?: number; lon?: number }) => g.lat !== undefined && g.lon !== undefined)
            .map((g: { lat: number; lon: number }) => [g.lon, g.lat] as [number, number]);
          if (ring.length >= 4) outerRings.push(ring);
        }
      }
      if (outerRings.length > 0) {
        features.push({
          type: 'Feature',
          properties: el.tags || {},
          geometry:
            outerRings.length === 1
              ? { type: 'Polygon', coordinates: [outerRings[0]] }
              : { type: 'MultiPolygon', coordinates: outerRings.map((r) => [r]) },
        });
      }
    }
  }

  return features;
}

interface OverpassElement {
  type: string;
  id: number;
  lat?: number;
  lon?: number;
  nodes?: number[];
  tags?: Record<string, string>;
  members?: Array<{
    type: string;
    role: string;
    geometry?: Array<{ lat: number; lon: number }>;
  }>;
}

async function queryOverpass(query: string): Promise<OverpassElement[]> {
  console.log('Fetching Overpass API...');
  console.log('Query:', query.substring(0, 200) + '...');

  const response = await fetch(OVERPASS_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `data=${encodeURIComponent(query)}`,
  });

  if (response.status === 429) {
    console.warn('Overpass API rate limited (429). Waiting 30s before retry...');
    await new Promise((r) => setTimeout(r, 30000));
    return queryOverpass(query);
  }

  if (!response.ok) {
    throw new Error(`Overpass API error: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  const size = JSON.stringify(data).length;
  console.log(`Overpass response received: ${(size / 1024 / 1024).toFixed(2)} MB, ${data.elements.length} elements`);
  return data.elements;
}

export async function loadOSMLayers(): Promise<{
  surface: Feature[];
  parks: Feature[];
  water: Feature[];
  roads: Feature[];
  buildings: Feature[];
}> {
  console.log('Loading OSM layers...');

  // Single combined query for all layer types using Manhattan Island area
  const query = `
[out:json][timeout:120];
area["name"="Manhattan Island"]->.manhattan;

// Surface (land)
(
  relation["place"="island"]["name"="Manhattan Island"];
)->.surface;

// Parks
(
  way["leisure"="park"](area.manhattan);
  relation["leisure"="park"](area.manhattan);
)->.parks;

// Water
(
  way["natural"="water"](area.manhattan);
  relation["natural"="water"](area.manhattan);
  way["waterway"](area.manhattan);
)->.water;

// Roads
(
  way["highway"~"^(motorway|trunk|primary|secondary|tertiary|residential|service)$"](area.manhattan);
)->.roads;

// Buildings
(
  way["building"](area.manhattan);
  relation["building"](area.manhattan);
)->.buildings;

// Output all
(.surface; .parks; .water; .roads; .buildings;);
out body;
>;
out skel qt;
`;

  const elements = await queryOverpass(query);

  // Categorize elements by tags
  const surfaceEls: OverpassElement[] = [];
  const parkEls: OverpassElement[] = [];
  const waterEls: OverpassElement[] = [];
  const roadEls: OverpassElement[] = [];
  const buildingEls: OverpassElement[] = [];
  const nodeEls: OverpassElement[] = [];

  for (const el of elements) {
    if (el.type === 'node') {
      nodeEls.push(el);
      continue;
    }
    const tags = el.tags || {};
    if (tags['building']) {
      buildingEls.push(el);
    } else if (tags['leisure'] === 'park') {
      parkEls.push(el);
    } else if (tags['natural'] === 'water' || tags['waterway']) {
      waterEls.push(el);
    } else if (tags['highway']) {
      roadEls.push(el);
    } else if (tags['place'] === 'island' || (el.type === 'relation' && tags['name'] === 'Manhattan Island')) {
      surfaceEls.push(el);
    }
  }

  // Convert each category with shared nodes
  const allWithNodes = (category: OverpassElement[]) => [...category, ...nodeEls];

  const surface = elementsToGeoJSON(allWithNodes(surfaceEls));
  const parks = elementsToGeoJSON(allWithNodes(parkEls));
  const water = elementsToGeoJSON(allWithNodes(waterEls));
  const roads = elementsToGeoJSON(allWithNodes(roadEls));
  const buildings = elementsToGeoJSON(allWithNodes(buildingEls));

  console.log(`OSM layers loaded - Surface: ${surface.length}, Parks: ${parks.length}, Water: ${water.length}, Roads: ${roads.length}, Buildings: ${buildings.length}`);

  return { surface, parks, water, roads, buildings };
}

