import { scaleSequential } from 'd3-scale';
import { interpolateYlOrRd } from 'd3-interpolate';

export function createNoiseColorScale(maxNoise: number) {
  const scale = scaleSequential(interpolateYlOrRd).domain([0, maxNoise]);

  return (noiseCount: number): [number, number, number, number] => {
    if (noiseCount === 0) return [180, 180, 180, 200]; // gray for no noise
    const color = scale(noiseCount);
    // Parse "rgb(r, g, b)" string
    const match = color.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
    if (match) {
      return [parseInt(match[1]), parseInt(match[2]), parseInt(match[3]), 220];
    }
    return [255, 100, 50, 220];
  };
}

export const SELECTED_COLOR: [number, number, number, number] = [0, 200, 255, 255];
export const HIGHLIGHTED_COLOR: [number, number, number, number] = [255, 255, 0, 255];

